sql:
SELECT user_id, passed
FROM user_action_summary
WHERE passed = (
  SELECT MAX(passed)
  FROM user_action_summary
);

SELECT COUNT(DISTINCT user_id)
FROM action_logs
WHERE action_id = 1 AND activity_id IS NULL;

SELECT AVG(duration) AS average_duration
FROM action_logs
WHERE user_id = 1;

SELECT COUNT(*)
FROM action_metrics
WHERE metric_value > 5;

external_knowledge:
- 'ventured into' refers to the 'discovered' action;
- 'undiscovered territories' are represented by actions where the 'discovered' metric value is greater than five;
- 'early explorers' refer to users ordered by the earliest timestamp of their actions;
- 'pioneers in the digital frontier' is a metaphorical reference to users who are active in discovering new actions in the system.

sql:
SELECT 
    (SELECT COUNT(*) FROM user_action_summary WHERE passed > 5) AS total_passed_over_5,
    (SELECT AVG(started) FROM user_action_summary WHERE discovered > 5) AS avg_started_over_5;

SELECT user_id, SUM(duration) 
FROM action_logs 
GROUP BY user_id;
